//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Table & cell borders: conflict resolution and inside-edge cascade".
//!
//! Each `#[test]` encodes a behaviour the OOXML / Word specification requires of
//! a faithful DOCX engine. A FAILING assertion here is NOT a flaky test to be
//! silenced: it encodes a real Word-compliance GAP in stemma (the engine
//! diverges from how Microsoft Word consumes / serializes the markup). The fix
//! is in the engine (model + serializer), never in weakening the assertion.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an unedited doc reflects stemma's
//! verbatim-preservation contract, NOT Word's render normalization. The xml*
//! checks below are therefore only used for markup stemma's serializer ACTIVELY
//! generates/restructures — tables are reconstructed from the typed model, so a
//! cell/row property the typed model does not carry is genuinely DROPPED on save
//! (true content loss), and child ORDERING is genuinely the serializer's job.
//! Consumption semantics (winner-selection) are also serializer-emitted here
//! because stemma materializes the effective edge from the typed model.

use std::io::Write;
use zip::write::FileOptions;

use stemma::api::Document;
use stemma::{DocxRuntime, ExportOptions};

// ─── Prelude / helpers ───────────────────────────────────────────────────────

/// Build a minimal, valid `.docx` whose `word/document.xml` wraps `body_xml` in
/// `<w:document><w:body>…</w:body></w:document>`. `extra_parts` are additional
/// parts under `word/` (e.g. `("styles.xml", "<…/>")`); each gets a
/// content-type Override and is written into the zip.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#,
    );

    // Content types: defaults + the always-present document.xml override, plus an
    // override per extra part. Map a part's content type from its extension/name.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let ct = match *name {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: unknown extra part content-type for {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{name}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, contents) in extra_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(contents.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return its `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    let bytes = archive
        .get("word/document.xml")
        .expect("word/document.xml present")
        .to_vec();
    String::from_utf8(bytes).expect("document.xml is utf8")
}

/// Parse then re-serialize (`Document::parse` → `serialize` → unzip), returning
/// the emitted `word/document.xml`. This is the engine's serializer output.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Translation of an `xmlRegex` of the simple shape `A ... B` (ordering, with
/// optional intervening markup) into a no-regex check: returns true iff `a`
/// occurs and `b` occurs at a later byte offset. Used because the `regex` crate
/// is not a dev-dependency of this crate; for the ordering specs below this is
/// faithful (top-before-bottom is exactly "first index of top < first index of
/// bottom").
fn ordered(xml: &str, a: &str, b: &str) -> bool {
    match (xml.find(a), xml.find(b)) {
        (Some(ia), Some(ib)) => ia < ib,
        _ => false,
    }
}

/// Assert the document opens clean (validator reports no errors).
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok,
        "{rule} — expected opens-clean (validate ok), got issues: {:?}",
        report.issues
    );
}

