    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("w:tblPrEx"),
        "ISO 29500-1 §17.4.39 / MS-OI29500 §2.1.169: tblPrEx carries the row's exception borders (a distinct cascade tier: cell -> table style -> tblPrEx -> table borders); a faithful engine must re-emit it. Its absence after roundtrip drops the row override entirely. Reserialized XML: {xml}"
    );
