#[test]
fn tcborders_child_edges_in_annex_a_sequence() {
    // Input deliberately lists bottom BEFORE top; the serializer must normalize
    // to the CT_TcBorders schema sequence (top precedes bottom).
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcBorders><w:bottom w:val="single" w:sz="6" w:space="0" w:color="00FF00"/><w:top w:val="single" w:sz="4" w:space="0" w:color="FF0000"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>x</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:top[^>]*/>\s*<w:bottom` translated to an ordering check (no
    // regex crate dev-dep): assert w:top occurs before w:bottom in tcBorders.
    assert!(
        ordered(&xml, "<w:top", "<w:bottom"),
        "ISO 29500-1 §17.4.66 / Annex A CT_TcBorders sequence: top must precede bottom regardless of input order; the engine must re-order to schema sequence. Reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "Emitting tcBorders children in schema order keeps the document valid; Word opens without repair.",
    );
}

#[test]
fn nonzero_cell_spacing_preserves_both_opposing_cell_borders() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/><w:tblCellSpacing w:w="40" w:type="dxa"/></w:tblPr><w:tr><w:tc><w:tcPr><w:tcW w:w="2500" w:type="dxa"/><w:tcBorders><w:right w:val="single" w:sz="24" w:space="0" w:color="FF0000"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>a</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2500" w:type="dxa"/><w:tcBorders><w:left w:val="single" w:sz="4" w:space="0" w:color="0000FF"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>b</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:color="FF0000""#),
        "ISO 29500-1 §17.4.66 / MS-OI29500 §2.1.150: with non-zero cell spacing the left cell's heavy red right border must be preserved (no conflict, all borders display). Reserialized XML: {xml}"
    );
    assert!(
        xml.contains(r#"w:color="0000FF""#),
        "ISO 29500-1 §17.4.66: the right cell's thin blue left border must ALSO be preserved — non-zero spacing means no winner-selection erases the weaker opposing border. Reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "tblCellSpacing + per-cell borders is valid markup; Word opens without repair.",
    );
}

#[test]
fn adjacent_shared_edge_dotdash_uses_ms_border_number_eight() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="dxa"/></w:tblPr><w:tblGrid><w:gridCol w:w="2500"/><w:gridCol w:w="2500"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2500" w:type="dxa"/><w:tcBorders><w:right w:val="dotDash" w:sz="8" w:space="0" w:color="FF0000"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>L</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2500" w:type="dxa"/><w:tcBorders><w:left w:val="single" w:sz="60" w:space="0" w:color="0000FF"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>R</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    // Word resolves an adjacent-cell border conflict at RENDER time (the heavier
    // border is "displayed"); it does NOT rewrite the saved markup, and neither
    // does stemma (the no-edit roundtrip is a verbatim passthrough). So the
    // resolution is materialized on stemma's CANONICAL model, which is the correct
    // surface to assert — not the re-serialized XML.
    let runtime = stemma::SimpleRuntime::new();
    let import = runtime.import_docx(&b).expect("import");
    let view = runtime.view(&import.doc_handle).expect("view");
    let table = view
        .canonical
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            stemma::BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("table present");

    let left_right = table.rows[0].cells[0]
        .formatting
        .borders
        .as_ref()
        .and_then(|bd| bd.right.as_ref())
        .expect("left cell right border after conflict resolution");
    let right_left = table.rows[0].cells[1]
        .formatting
        .borders
        .as_ref()
        .and_then(|bd| bd.left.as_ref())
        .expect("right cell left border after conflict resolution");

    // dotDash sz=8 -> weight 8*8=64 (border-number 8); single sz=60 -> 60*1=60.
    assert_eq!(
        left_right.style,
        stemma::BorderStyle::DotDash,
        "MS-OI29500 §2.1.169: dotDash (number 8, weight 64) beats single (weight 60); the left cell's right edge resolves to dotDash. got {left_right:?}"
    );
    assert_eq!(
        right_left.style,
        stemma::BorderStyle::DotDash,
        "MS-OI29500 §2.1.169: the resolved shared edge shows the single winner on BOTH cells; the right cell's left edge becomes dotDash. got {right_left:?}"
    );
    assert_eq!(
        right_left.color.as_deref(),
        Some("FF0000"),
        "MS-OI29500 §2.1.169: the winning border carries its own color (red) onto both edges. got {right_left:?}"
    );

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.169: resolved shared-edge borders open clean.",
    );
}

#[test]
fn cell_diagonal_tl2br_border_preserved_on_roundtrip() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="2500" w:type="dxa"/></w:tblPr><w:tblGrid><w:gridCol w:w="2500"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2500" w:type="dxa"/><w:tcBorders><w:tl2br w:val="double" w:sz="4" w:space="0" w:color="FF0000"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>X</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:tl2br"),
        "ISO 29500-1 §17.4.73: the diagonal exists only if tl2br is present; Word preserves it on save, so the re-serialized cell tcBorders must still contain a tl2br element. Reserialized XML: {xml}"
    );
    // xmlRegex `<w:tl2br [^>]*w:val="double"[^>]*w:color="FF0000"` — translated:
    // a tl2br edge is emitted with both its style and color intact.
    assert!(
        ordered(&xml, "<w:tl2br ", r#"w:val="double""#)
            && xml.contains(r#"w:val="double""#)
            && xml.contains(r#"w:color="FF0000""#),
        "ISO 29500-1 §17.4.73 references CT_Border (§17.3.4); the diagonal's style (double) and color (FF0000) must survive the round-trip unchanged. Reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.4.73 / §17.4.66: a tl2br diagonal is valid; Word opens without repair.",
    );
}

