#[test]
fn tcborders_child_ordering_follows_ct_tcborders_sequence() {
    // Input order is insideV, bottom, top; the serializer must emit
    // top -> bottom -> insideV per the CT_TcBorders sequence.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/><w:tcBorders><w:insideV w:val="single" w:sz="4" w:space="0" w:color="00FF00"/><w:bottom w:val="single" w:sz="8" w:space="0" w:color="000000"/><w:top w:val="single" w:sz="8" w:space="0" w:color="000000"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>R1C1</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:top[^>]*/>\s*<w:bottom[^>]*/>\s*<w:insideV[^>]*/>` —
    // translated to consecutive ordering: top < bottom < insideV.
    assert!(
        ordered(&xml, "<w:top", "<w:bottom") && ordered(&xml, "<w:bottom", "<w:insideV"),
        "ECMA-376 §17.4.66 / Annex A CT_TcBorders sequence requires top before bottom before insideV regardless of input order; the serializer must normalize ordering so Word opens clean. Reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "Correctly ordered CT_TcBorders children open without repair in Word (Annex A sequence).",
    );
}

#[test]
fn logical_start_end_cell_borders_emitted_as_left_right() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/><w:tcBorders><w:start w:val="single" w:sz="12" w:space="0" w:color="FF0000"/></w:tcBorders></w:tcPr><w:p><w:r><w:t>s</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:(left|start) w:val="single" w:sz="12"` — translated: the
    // start/left logical edge border must survive (as left after normalization,
    // or preserved as start), never dropped, carrying val=single sz=12.
    let left_ok = xml.contains(r#"<w:left w:val="single" w:sz="12""#);
    let start_ok = xml.contains(r#"<w:start w:val="single" w:sz="12""#);
    assert!(
        left_ok || start_ok,
        "ISO 29500-1 §17.4.66 / §17.4.38: the start/left logical edge border must survive re-serialization (as left after normalization, or preserved as start) — never dropped. Reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.4.66: left/right and start/end are both valid CT_TcBorders edges; the document opens without repair.",
    );
}
